using System;
using System.Collections.Generic;

// Interface
public interface IDrawable
{
    void Draw();
    string Describe { get; }
}

// Abstract base class
public abstract class Shape : IDrawable
{
    public string Color { get; }
    protected Shape(string color) => Color = color;

    public abstract double Area { get; }
    public abstract double Perimeter { get; }
    public virtual void Draw() => Console.WriteLine($"Drawing {Color} {GetType().Name}");
    public string Describe => $"{Color} {GetType().Name}: Area={Area:F2}";
}

// Concrete classes
public class Circle : Shape
{
    public double Radius { get; }
    public Circle(string color, double radius) : base(color) => Radius = radius;
    public override double Area => Math.PI * Radius * Radius;
    public override double Perimeter => 2 * Math.PI * Radius;
}

public class Rectangle : Shape
{
    public double Width { get; }
    public double Height { get; }
    public Rectangle(string color, double w, double h) : base(color)
    {
        Width = w; Height = h;
    }
    public override double Area => Width * Height;
    public override double Perimeter => 2 * (Width + Height);
}

// Extension method
public static class ShapeExtensions
{
    public static void PrintAll(this IEnumerable<Shape> shapes)
    {
        foreach (var s in shapes)
            Console.WriteLine(s.Describe);
    }
}

// Event system
public class Button
{
    public event EventHandler? Clicked;
    public string Label { get; }
    public Button(string label) => Label = label;
    public void Click() => Clicked?.Invoke(this, EventArgs.Empty);
}

// Usage
var shapes = new List<Shape>
{
    new Circle("Red", 5),
    new Rectangle("Blue", 4, 6),
    new Circle("Green", 3)
};
shapes.PrintAll();

var button = new Button("Submit");
button.Clicked += (sender, e) => Console.WriteLine("Button clicked!");
button.Click();
