// Method syntax
var csHonors = students
    .Where(s => s.Dept == "CS" && s.GPA >= 3.5)
    .OrderByDescending(s => s.GPA)
    .Select(s => new { s.Name, s.GPA })
    .ToList();

// Query syntax
var mathStudents = from s in students
                   where s.Dept == "Math"
                   orderby s.Age
                   select s;

// Grouping with aggregation
var byDept = students
    .GroupBy(s => s.Dept)
    .Select(g => new
    {
        Dept = g.Key,
        Count = g.Count(),
        AvgGPA = g.Average(s => s.GPA),
        Top = g.OrderByDescending(s => s.GPA).First().Name
    })
    .OrderByDescending(g => g.AvgGPA);

foreach (var d in byDept)
    Console.WriteLine($"{d.Dept}: {d.Count} students, avg {d.AvgGPA:F2}, top: {d.Top}");

// Aggregation
var stats = new
{
    Total = students.Count(),
    AvgGPA = students.Average(s => s.GPA),
    MaxGPA = students.Max(s => s.GPA)
