using System;
using System.Collections.Generic;
using System.Net.Http;
using System.Threading.Tasks;
using System.Linq;

public class AsyncDemo
{
    private static readonly HttpClient _client = new();

    // Async method returning Task<string>
    public static async Task<string> FetchUrlAsync(string url)
    {
        try
        {
            var response = await _client.GetAsync(url);
            response.EnsureSuccessStatusCode();
            return await response.Content.ReadAsStringAsync();
        }
        catch (HttpRequestException ex)
        {
            return $"Error: {ex.Message}";
        }
    }

    // Sequential awaits
    public static async Task<List<string>> FetchSequentialAsync(List<string> urls)
    {
        var results = new List<string>();
        foreach (var url in urls)
        {
            var content = await FetchUrlAsync(url);
            results.Add(content[..100]); // first 100 chars
        }
        return results;
    }

    // Parallel with Task.WhenAll
    public static async Task<List<string>> FetchParallelAsync(List<string> urls)
    {
        var tasks = urls.Select(FetchUrlAsync).ToList();
        var results = await Task.WhenAll(tasks);
        return results.Select(r => r[..100]).ToList();
    }

    // Cancellation
    public static async Task<string> FetchWithTimeoutAsync(string url, int ms)
    {
        using var cts = new CancellationTokenSource(ms);
        try
        {
            return await FetchUrlAsync(url).WaitAsync(cts.Token);
        }
        catch (OperationCanceledException)
        {
            return "Timeout!";
        }
    }

    // IAsyncEnumerable (C# 8+)
    public static async IAsyncEnumerable<int> GenerateAsync(int count)
    {
        for (int i = 0; i < count; i++)
        {
            await Task.Delay(100);
            yield return i;
        }
    }

    public static async Task Main()
    {
        // Parallel fetch
        var urls = new List<string>
        {
            "https://httpbin.org/get",
            "https://httpbin.org/ip",
            "https://httpbin.org/user-agent"
        };

        var results = await FetchParallelAsync(urls);
        foreach (var r in results)
            Console.WriteLine(r);

        // Async enumerable
        await foreach (var num in GenerateAsync(5))
            Console.WriteLine(num);
    }
}
