using System;
using System.Collections.Generic;
using System.Collections.Immutable;
using System.Linq;

public class CollectionsDemo
{
    public static void Main()
    {
        // List<T>
        var names = new List<string> { "Alice", "Bob", "Charlie" };
        names.Add("Diana");
        names.RemoveAt(0);
        names.Sort();
        Console.WriteLine(string.Join(", ", names));

        // Dictionary<TKey, TValue>
        var scores = new Dictionary<string, int>
        {
            ["Alice"] = 95,
            ["Bob"] = 87,
            ["Charlie"] = 92
        };
        scores.TryAdd("Alice", 100); // won't overwrite
        if (scores.TryGetValue("Bob", out int bobScore))
            Console.WriteLine($"Bob: {bobScore}");

        // HashSet<T>
        var set1 = new HashSet<int> { 1, 2, 3, 4 };
        var set2 = new HashSet<int> { 3, 4, 5, 6 };
        Console.WriteLine($"Union: {string.Join(", ", set1.Union(set2))}");
        Console.WriteLine($"Intersect: {string.Join(", ", set1.Intersect(set2))}");

        // Immutable collections
        var immutable = ImmutableList.Create(1, 2, 3);
        var updated = immutable.Add(4); // returns new list
        Console.WriteLine($"Original: {immutable.Count}, Updated: {updated.Count}");

        // SortedDictionary
        var sorted = new SortedDictionary<string, int>(scores);
        foreach (var kvp in sorted)
            Console.WriteLine($"  {kvp.Key}: {kvp.Value}");

        // Queue and Stack
        var queue = new Queue<string>();
        queue.Enqueue("first");
        queue.Enqueue("second");
        Console.WriteLine(queue.Dequeue()); // first

        var stack = new Stack<string>();
        stack.Push("bottom");
        stack.Push("top");
        Console.WriteLine(stack.Pop()); // top
    }
}

