// Event system
class OrderProcessor
{
    public event EventHandler<OrderEventArgs>? OrderPlaced;
    public event EventHandler<OrderEventArgs>? OrderShipped;

    public void PlaceOrder(string product, int quantity)
    {
        Console.WriteLine($"Processing order: {quantity}x {product}");
        OrderPlaced?.Invoke(this, new OrderEventArgs(product, quantity));
    }

    public void ShipOrder(string product)
    {
        Console.WriteLine($"Shipping: {product}");
        OrderShipped?.Invoke(this, new OrderEventArgs(product, 0));
    }
}

class OrderEventArgs : EventArgs
{
    public string Product { get; }
    public int Quantity { get; }
    public DateTime Timestamp { get; }

    public OrderEventArgs(string product, int quantity)
    {
        Product = product;
        Quantity = quantity;
        Timestamp = DateTime.Now;
    }
}

// Observer pattern with Func/Action
class EventBus
{
    private readonly Dictionary<string, List<Action<object>>> _handlers = new();

    public void Subscribe(string eventName, Action<object> handler)
    {
        if (!_handlers.ContainsKey(eventName))
            _handlers[eventName] = new List<Action<object>>();
        _handlers[eventName].Add(handler);
    }

    public void Publish(string eventName, object data)
    {
        if (_handlers.TryGetValue(eventName, out var handlers))
            foreach (var handler in handlers)
                handler(data);
    }
}

// Usage
var processor = new OrderProcessor();
processor.OrderPlaced += (sender, e) =>
    Console.WriteLine($"[LOG] Order placed: {e.Product} at {e.Timestamp}");
processor.OrderPlaced += (sender, e) =>
    Console.WriteLine($"[EMAIL] Confirmation sent for {e.Product}");
processor.OrderShipped += (sender, e) =>
    Console.WriteLine($"[TRACK] {e.Product} shipped");

processor.PlaceOrder("Laptop", 2);
processor.ShipOrder("Laptop");

