using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.DependencyInjection;
using System.ComponentModel.DataAnnotations;

// Program.cs — Minimal API style
var builder = WebApplication.CreateBuilder(args);
builder.Services.AddSingleton<IUserRepository, InMemoryUserRepository>();
builder.Services.AddScoped<IEmailService, SmtpEmailService>();

var app = builder.Build();

// Middleware pipeline
app.Use(async (context, next) =>
{
    var start = DateTime.UtcNow;
    await next();
    var elapsed = DateTime.UtcNow - start;
    Console.WriteLine($"{context.Request.Path} took {elapsed.TotalMilliseconds}ms");
});

// Endpoints
app.MapGet("/users", (IUserRepository repo) =>
    Results.Ok(repo.GetAll()));

app.MapGet("/users/{id:int}", (int id, IUserRepository repo) =>
    repo.GetById(id) is User user
        ? Results.Ok(user)
        : Results.NotFound());

app.MapPost("/users", (UserDto dto, IUserRepository repo) =>
{
    var user = new User(dto.Name, dto.Email);
    repo.Add(user);
    return Results.Created($"/users/{user.Id}", user);
});

app.Run();

// Models
public record User(string Name, string Email)
{
    public int Id { get; init; }
}

public record UserDto(
    [property: Required, MinLength(2)] string Name,
    [property: Required, EmailAddress] string Email
);

// Service interfaces
public interface IUserRepository
{
    IEnumerable<User> GetAll();
    User? GetById(int id);
    void Add(User user);
}

public interface IEmailService
{
    Task SendAsync(string to, string subject, string body);
}

// Implementations
public class InMemoryUserRepository : IUserRepository
{
    private readonly List<User> _users = new();
    private int _nextId = 1;

    public IEnumerable<User> GetAll() => _users;
    public User? GetById(int id) => _users.FirstOrDefault(u => u.Id == id);
    public void Add(User user)
    {
        _users.Add(user with { Id = _nextId++ });
    }
}

public class SmtpEmailService : IEmailService
{
    public async Task SendAsync(string to, string subject, string body)
    {
        await Task.Delay(100); // simulate SMTP
        Console.WriteLine($"Email sent to {to}: {subject}");
    }
}
